const t=JSON.parse('{"key":"v-62a2509a","path":"/research/basic/envs/1.python.html","title":"Anaconda 安装和使用","lang":"zh-CN","frontmatter":{"title":"Anaconda 安装和使用","description":"1 基础介绍 Python是当前深度学习领域最为流行的编程语言，它较为现代化，更方便学习和使用。得益于众多开源第三方包的支持，Python具有非常强大的功能。尽管作为一种解释型语言，Python直接编写的代码在性能上和C/C++、Java等语言存在一定的差距，但众多第三方包在底层的计算上依然使用C/C++等进行实现，因此Python的性能依然非常强大。但也由于Python众多的第三方库，对这些数量庞大的库进行管理是一件非常复杂的事情。 Anaconda提供了对Python包管理的机制，可以创建多个相互隔离的环境空间，每个环境中可以独立的安装各种第三方库。这样的好处是在同时开发多个项目时，不同项目之间的环境配置完全隔离，也避免了不同包之间依赖关系可能导致的潜在问题。","head":[["meta",{"property":"og:url","content":"https://xinzwang.github.io/research/basic/envs/1.python.html"}],["meta",{"property":"og:title","content":"Anaconda 安装和使用"}],["meta",{"property":"og:description","content":"1 基础介绍 Python是当前深度学习领域最为流行的编程语言，它较为现代化，更方便学习和使用。得益于众多开源第三方包的支持，Python具有非常强大的功能。尽管作为一种解释型语言，Python直接编写的代码在性能上和C/C++、Java等语言存在一定的差距，但众多第三方包在底层的计算上依然使用C/C++等进行实现，因此Python的性能依然非常强大。但也由于Python众多的第三方库，对这些数量庞大的库进行管理是一件非常复杂的事情。 Anaconda提供了对Python包管理的机制，可以创建多个相互隔离的环境空间，每个环境中可以独立的安装各种第三方库。这样的好处是在同时开发多个项目时，不同项目之间的环境配置完全隔离，也避免了不同包之间依赖关系可能导致的潜在问题。"}],["meta",{"property":"og:type","content":"article"}],["meta",{"property":"og:locale","content":"zh-CN"}],["meta",{"property":"og:updated_time","content":"2023-04-15T06:40:37.000Z"}],["meta",{"property":"article:author","content":"Wang Xinzhe"}],["meta",{"property":"article:modified_time","content":"2023-04-15T06:40:37.000Z"}],["script",{"type":"application/ld+json"},"{\\"@context\\":\\"https://schema.org\\",\\"@type\\":\\"Article\\",\\"headline\\":\\"Anaconda 安装和使用\\",\\"image\\":[\\"\\"],\\"dateModified\\":\\"2023-04-15T06:40:37.000Z\\",\\"author\\":[{\\"@type\\":\\"Person\\",\\"name\\":\\"Wang Xinzhe\\",\\"url\\":\\"https://xinzwang.github.io\\"}]}"]]},"headers":[{"level":2,"title":"1 基础介绍","slug":"_1-基础介绍","link":"#_1-基础介绍","children":[]},{"level":2,"title":"2 安装","slug":"_2-安装","link":"#_2-安装","children":[{"level":3,"title":"2.1 下载安装包","slug":"_2-1-下载安装包","link":"#_2-1-下载安装包","children":[]},{"level":3,"title":"2.2 进行安装","slug":"_2-2-进行安装","link":"#_2-2-进行安装","children":[]},{"level":3,"title":"2.3 配置环境变量","slug":"_2-3-配置环境变量","link":"#_2-3-配置环境变量","children":[]},{"level":3,"title":"2.4 验证安装是否成功","slug":"_2-4-验证安装是否成功","link":"#_2-4-验证安装是否成功","children":[]}]},{"level":2,"title":"3 使用","slug":"_3-使用","link":"#_3-使用","children":[{"level":3,"title":"3.1 虚拟环境管理","slug":"_3-1-虚拟环境管理","link":"#_3-1-虚拟环境管理","children":[]},{"level":3,"title":"3.2 环境包管理","slug":"_3-2-环境包管理","link":"#_3-2-环境包管理","children":[]}]}],"git":{"createdTime":1681540837000,"updatedTime":1681540837000,"contributors":[{"name":"wxz","email":"1790828743@qq.com","commits":1}]},"readingTime":{"minutes":3.83,"words":1148},"filePathRelative":"research/basic/envs/1.python.md","localizedDate":"2023年4月15日","excerpt":"<h2> 1 基础介绍</h2>\\n<p>Python是当前深度学习领域最为流行的编程语言，它较为现代化，更方便学习和使用。得益于众多开源第三方包的支持，Python具有非常强大的功能。尽管作为一种解释型语言，Python直接编写的代码在性能上和C/C++、Java等语言存在一定的差距，但众多第三方包在底层的计算上依然使用C/C++等进行实现，因此Python的性能依然非常强大。但也由于Python众多的第三方库，对这些数量庞大的库进行管理是一件非常复杂的事情。</p>\\n<p>Anaconda提供了对Python包管理的机制，可以创建多个相互隔离的环境空间，每个环境中可以独立的安装各种第三方库。这样的好处是在同时开发多个项目时，不同项目之间的环境配置完全隔离，也避免了不同包之间依赖关系可能导致的潜在问题。</p>","autoDesc":true}');export{t as data};
